// api/warehouse-router.ts
init_drizzle_orm();
init_connection();
init_schema2();
var warehouseRouter = createRouter({
  // ===== WAREHOUSES =====
  warehouseList: publicQuery.query(async () => {
    const db2 = getDb();
    return await db2.select().from(warehouses).orderBy(warehouses.name);
  }),
  warehouseCreate: publicQuery.input(external_exports.object({
    code: external_exports.string().min(1),
    name: external_exports.string().min(1),
    type: external_exports.enum(["raw_materials", "finished_goods", "construction_site", "other"]),
    address: external_exports.string().optional()
  })).mutation(async ({ input }) => {
    const db2 = getDb();
    await db2.insert(warehouses).values(input);
    return { success: true };
  }),
  warehouseUpdate: publicQuery.input(external_exports.object({
    id: external_exports.number(),
    code: external_exports.string().optional(),
    name: external_exports.string().optional(),
    type: external_exports.enum(["raw_materials", "finished_goods", "construction_site", "other"]).optional(),
    address: external_exports.string().optional(),
    isActive: external_exports.enum(["active", "inactive"]).optional()
  })).mutation(async ({ input }) => {
    const db2 = getDb();
    const { id, ...data } = input;
    await db2.update(warehouses).set(data).where(eq(warehouses.id, id));
    return { success: true };
  }),
  // ===== MATERIAL STOCK BY WAREHOUSE =====
  materialStockList: publicQuery.input(external_exports.object({ warehouseId: external_exports.number().optional(), materialId: external_exports.number().optional() }).optional()).query(async ({ input }) => {
    const db2 = getDb();
    let query = db2.select({
      id: materialStock.id,
      materialId: materialStock.materialId,
      warehouseId: materialStock.warehouseId,
      quantity: materialStock.quantity,
      avgCost: materialStock.avgCost,
      materialName: materials.name,
      materialCode: materials.code,
      materialUnit: materials.unit
    }).from(materialStock).leftJoin(materials, eq(materialStock.materialId, materials.id));
    const result = await query;
    let filtered = result;
    if (input?.warehouseId) filtered = filtered.filter((r) => r.warehouseId === input.warehouseId);
    if (input?.materialId) filtered = filtered.filter((r) => r.materialId === input.materialId);
    return filtered;
  }),
  // ===== STOCK TRANSFERS =====
  transferList: publicQuery.input(external_exports.object({ status: external_exports.string().optional() }).optional()).query(async ({ input }) => {
    const db2 = getDb();
    const result = await db2.select().from(stockTransfers).orderBy(desc(stockTransfers.createdAt));
    if (input?.status) return result.filter((r) => r.status === input.status);
    return result;
  }),
  transferById: publicQuery.input(external_exports.object({ id: external_exports.number() })).query(async ({ input }) => {
    const db2 = getDb();
    const t2 = await db2.select().from(stockTransfers).where(eq(stockTransfers.id, input.id));
    if (!t2[0]) return null;
    const items = await db2.select().from(stockTransferItems).where(eq(stockTransferItems.transferId, input.id));
    return { ...t2[0], items };
  }),
  transferCreate: publicQuery.input(external_exports.object({
    transferNumber: external_exports.string().min(1),
    fromWarehouseId: external_exports.number(),
    toWarehouseId: external_exports.number(),
    status: external_exports.enum(["draft", "confirmed", "cancelled"]).default("draft"),
    transferDate: external_exports.string(),
    notes: external_exports.string().optional(),
    items: external_exports.array(external_exports.object({
      materialId: external_exports.number(),
      quantity: external_exports.string(),
      unitCost: external_exports.string().optional(),
      notes: external_exports.string().optional()
    })).optional()
  })).mutation(async ({ input }) => {
    const db2 = getDb();
    const { items, ...data } = input;
    const result = await db2.insert(stockTransfers).values({
      ...data,
      transferDate: new Date(data.transferDate)
    });
    const insertId = Number(result[0].insertId);
    if (items && items.length > 0) {
      await db2.insert(stockTransferItems).values(items.map((i) => ({ ...i, transferId: insertId })));
    }
    return { success: true, id: insertId };
  }),
  transferConfirm: publicQuery.input(external_exports.object({ id: external_exports.number() })).mutation(async ({ input }) => {
    const db2 = getDb();
    const transfer = await db2.select().from(stockTransfers).where(eq(stockTransfers.id, input.id));
    if (!transfer[0]) throw new Error("\u041F\u0440\u0435\u043D\u043E\u0441\u043E\u0442 \u043D\u0435 \u043F\u043E\u0441\u0442\u043E\u0438");
    if (transfer[0].status !== "draft") throw new Error("\u0421\u0430\u043C\u043E \u043D\u0430\u0446\u0440\u0442 \u043C\u043E\u0436\u0435 \u0434\u0430 \u0441\u0435 \u043F\u043E\u0442\u0432\u0440\u0434\u0438");
    const items = await db2.select().from(stockTransferItems).where(eq(stockTransferItems.transferId, input.id));
    for (const item of items) {
      const fromStock = await db2.select().from(materialStock).where(and(
        eq(materialStock.materialId, item.materialId),
        eq(materialStock.warehouseId, transfer[0].fromWarehouseId)
      ));
      if (fromStock[0]) {
        const newQty = parseFloat(fromStock[0].quantity) - parseFloat(item.quantity);
        if (newQty < 0) throw new Error(`\u041D\u0435\u043C\u0430 \u0434\u043E\u0432\u043E\u043B\u043D\u043E \u0437\u0430\u043B\u0438\u0445\u0430 \u0437\u0430 \u043C\u0430\u0442\u0435\u0440\u0438\u0458\u0430\u043B ${item.materialId}`);
        await db2.update(materialStock).set({ quantity: newQty.toFixed(3) }).where(eq(materialStock.id, fromStock[0].id));
      }
      const toStock = await db2.select().from(materialStock).where(and(
        eq(materialStock.materialId, item.materialId),
        eq(materialStock.warehouseId, transfer[0].toWarehouseId)
      ));
      if (toStock[0]) {
        await db2.update(materialStock).set({ quantity: (parseFloat(toStock[0].quantity) + parseFloat(item.quantity)).toFixed(3) }).where(eq(materialStock.id, toStock[0].id));
      } else {
        await db2.insert(materialStock).values({
          materialId: item.materialId,
          warehouseId: transfer[0].toWarehouseId,
          quantity: item.quantity,
          avgCost: item.unitCost ?? "0"
        });
      }
      await db2.insert(inventoryTransactions).values({
        materialId: item.materialId,
        warehouseId: transfer[0].fromWarehouseId,
        type: "transfer_out",
        quantity: item.quantity,
        unitCost: item.unitCost,
        totalCost: item.unitCost ? (parseFloat(item.unitCost) * parseFloat(item.quantity)).toFixed(2) : null,
        sourceDocType: "transfer",
        sourceDocId: input.id,
        reference: transfer[0].transferNumber
      });
      await db2.insert(inventoryTransactions).values({
        materialId: item.materialId,
        warehouseId: transfer[0].toWarehouseId,
        type: "transfer_in",
        quantity: item.quantity,
        unitCost: item.unitCost,
        totalCost: item.unitCost ? (parseFloat(item.unitCost) * parseFloat(item.quantity)).toFixed(2) : null,
        sourceDocType: "transfer",
        sourceDocId: input.id,
        reference: transfer[0].transferNumber
      });
    }
    await db2.update(stockTransfers).set({ status: "confirmed" }).where(eq(stockTransfers.id, input.id));
    await logAudit({ action: "CONFIRM", entityType: "stock_transfer", entityId: input.id, description: `\u041F\u043E\u0442\u0432\u0440\u0434\u0435\u043D \u043F\u0440\u0435\u043D\u043E\u0441 ${transfer[0].transferNumber}` });
    return { success: true };
  }),
  // ===== INVENTORY COUNTS (POPIS) =====
  countList: publicQuery.query(async () => {
    const db2 = getDb();
    return await db2.select().from(inventoryCounts).orderBy(desc(inventoryCounts.createdAt));
  }),
  countById: publicQuery.input(external_exports.object({ id: external_exports.number() })).query(async ({ input }) => {
    const db2 = getDb();
    const c = await db2.select().from(inventoryCounts).where(eq(inventoryCounts.id, input.id));
    if (!c[0]) return null;
    const items = await db2.select({
      id: inventoryCountItems.id,
      countId: inventoryCountItems.countId,
      materialId: inventoryCountItems.materialId,
      systemQty: inventoryCountItems.systemQty,
      countedQty: inventoryCountItems.countedQty,
      difference: inventoryCountItems.difference,
      unitCost: inventoryCountItems.unitCost,
      totalDifference: inventoryCountItems.totalDifference,
      notes: inventoryCountItems.notes,
      materialName: materials.name,
      materialCode: materials.code
    }).from(inventoryCountItems).leftJoin(materials, eq(inventoryCountItems.materialId, materials.id)).where(eq(inventoryCountItems.countId, input.id));
    return { ...c[0], items };
  }),
  countCreate: publicQuery.input(external_exports.object({
    countNumber: external_exports.string().min(1),
    warehouseId: external_exports.number(),
    countDate: external_exports.string(),
    notes: external_exports.string().optional()
  })).mutation(async ({ input }) => {
    const db2 = getDb();
    const currentStock = await db2.select().from(materialStock).where(eq(materialStock.warehouseId, input.warehouseId));
    const result = await db2.insert(inventoryCounts).values({
      ...input,
      countDate: new Date(input.countDate)
    });
    const insertId = Number(result[0].insertId);
    for (const s of currentStock) {
      await db2.insert(inventoryCountItems).values({
        countId: insertId,
        materialId: s.materialId,
        systemQty: s.quantity,
        countedQty: s.quantity,
        // default to system qty
        difference: "0",
        unitCost: s.avgCost,
        totalDifference: "0"
      });
    }
    return { success: true, id: insertId };
  }),
  countUpdateItem: publicQuery.input(external_exports.object({
    id: external_exports.number(),
    countedQty: external_exports.string(),
    notes: external_exports.string().optional()
  })).mutation(async ({ input }) => {
    const db2 = getDb();
    const { id, countedQty, notes } = input;
    const item = await db2.select().from(inventoryCountItems).where(eq(inventoryCountItems.id, id));
    if (!item[0]) throw new Error("\u0421\u0442\u0430\u0432\u043A\u0430\u0442\u0430 \u043D\u0435 \u043F\u043E\u0441\u0442\u043E\u0438");
    const diff = parseFloat(countedQty) - parseFloat(item[0].systemQty ?? "0");
    const totalDiff = diff * parseFloat(item[0].unitCost ?? "0");
    await db2.update(inventoryCountItems).set({
      countedQty,
      difference: diff.toFixed(3),
      totalDifference: totalDiff.toFixed(2),
      notes: notes ?? item[0].notes
    }).where(eq(inventoryCountItems.id, id));
    return { success: true };
  }),
  countComplete: publicQuery.input(external_exports.object({ id: external_exports.number() })).mutation(async ({ input }) => {
    const db2 = getDb();
    const count2 = await db2.select().from(inventoryCounts).where(eq(inventoryCounts.id, input.id));
    if (!count2[0]) throw new Error("\u041F\u043E\u043F\u0438\u0441\u043E\u0442 \u043D\u0435 \u043F\u043E\u0441\u0442\u043E\u0438");
    const items = await db2.select().from(inventoryCountItems).where(eq(inventoryCountItems.countId, input.id));
    for (const item of items) {
      const diff = parseFloat(item.difference ?? "0");
      if (diff === 0) continue;
      const stock = await db2.select().from(materialStock).where(and(
        eq(materialStock.materialId, item.materialId),
        eq(materialStock.warehouseId, count2[0].warehouseId)
      ));
      if (stock[0]) {
        const newQty = (parseFloat(stock[0].quantity) + diff).toFixed(3);
        await db2.update(materialStock).set({ quantity: newQty }).where(eq(materialStock.id, stock[0].id));
      }
      await db2.insert(inventoryTransactions).values({
        materialId: item.materialId,
        warehouseId: count2[0].warehouseId,
        type: "adjustment",
        quantity: Math.abs(diff).toFixed(3),
        unitCost: item.unitCost,
        totalCost: item.totalDifference,
        sourceDocType: "inventory_count",
        sourceDocId: input.id,
        reference: count2[0].countNumber,
        notes: diff > 0 ? "\u0412\u0438\u0448\u043E\u043A \u043F\u0440\u0438 \u043F\u043E\u043F\u0438\u0441" : "\u041A\u0443\u0441\u043E\u043A \u043F\u0440\u0438 \u043F\u043E\u043F\u0438\u0441"
      });
    }
    await db2.update(inventoryCounts).set({ status: "completed" }).where(eq(inventoryCounts.id, input.id));
    await logAudit({ action: "CONFIRM", entityType: "inventory_count", entityId: input.id, description: `\u0417\u0430\u0432\u0440\u0448\u0435\u043D \u043F\u043E\u043F\u0438\u0441 ${count2[0].countNumber}` });
    return { success: true };
  })
});

