var emailRouter = createRouter({
  // Провери дали има конфигурација
  saveConfig: publicQuery.input(external_exports.object({
    host: external_exports.string().min(1),
    port: external_exports.number().default(993),
    secure: external_exports.boolean().default(true),
    username: external_exports.string().min(1),
    password: external_exports.string().min(1)
  })).mutation(async ({ input }) => {
    const db2 = getDb();
    const { companySettings: companySettings2 } = await Promise.resolve().then(() => (init_schema2(), schema_exports));
    const existing = await db2.select().from(companySettings2);
    const vals = {
      emailImapHost: input.host,
      emailImapPort: input.port,
      emailImapSecure: input.secure ? 1 : 0,
      emailUsername: input.username,
      emailPassword: input.password
    };
    if (existing[0]) {
      const { eq: eq3 } = await Promise.resolve().then(() => (init_drizzle_orm(), drizzle_orm_exports));
      await db2.update(companySettings2).set(vals).where(eq3(companySettings2.id, existing[0].id));
    } else {
      await db2.insert(companySettings2).values({ name: "Serafimoski Tech DOOEL", valuationMethod: "fifo", timezone: "Europe/Skopje", edb: "", embs: "", address: "", bankName: "", bankAccount: "", ...vals });
    }
    return { success: true };
  }),
  hasConfig: publicQuery.query(async () => {
    const config2 = await getEmailConfig();
    return {
      configured: !!config2,
      username: config2?.username ?? null
    };
  }),
  // Донеси фактури од е-маил
  fetchEmails: publicQuery.input(external_exports.object({
    sinceDays: external_exports.number().min(1).max(30).default(7)
  }).optional()).mutation(async ({ input }) => {
    const config2 = await getEmailConfig();
    if (!config2) {
      return {
        success: false,
        message: "\u041D\u0435\u043C\u0430 \u043A\u043E\u043D\u0444\u0438\u0433\u0443\u0440\u0438\u0440\u0430\u043D\u043E \u0435-\u043C\u0430\u0438\u043B. \u041E\u0434\u0435\u0442\u0435 \u0432\u043E \u041F\u043E\u0434\u0435\u0441\u0443\u0432\u0430\u045A\u0430 -> \u0424\u0438\u0440\u043C\u0430 \u0438 \u0432\u043D\u0435\u0441\u0435\u0442\u0435 IMAP \u043F\u043E\u0434\u0430\u0442\u043E\u0446\u0438.",
        invoices: []
      };
    }
    try {
      const fetched = await fetchInvoicesFromEmail(config2, input?.sinceDays ?? 7);
      if (fetched.length === 0) {
        return {
          success: true,
          message: "\u041D\u0435\u043C\u0430 \u043D\u043E\u0432\u0438 \u0444\u0430\u043A\u0442\u0443\u0440\u0438 \u0432\u043E \u0435-\u043C\u0430\u0438\u043B\u043E\u0442.",
          invoices: []
        };
      }
      const storedIds = [];
      for (const inv of fetched) {
        const db2 = getDb();
        const existing = await db2.select({ id: emailInvoices.id }).from(emailInvoices).where(
          inv.pdfFilename ? eq(emailInvoices.pdfFilename, inv.pdfFilename) : eq(emailInvoices.subject, inv.subject)
        ).limit(1);
        if (existing[0]) continue;
        const id = await storeEmailInvoice(inv);
        storedIds.push(id);
      }
      return {
        success: true,
        message: `\u041F\u0440\u043E\u043D\u0430\u0458\u0434\u0435\u043D\u0438 ${fetched.length} \u0444\u0430\u043A\u0442\u0443\u0440\u0438, \u0437\u0430\u0447\u0443\u0432\u0430\u043D\u0438 ${storedIds.length} \u043D\u043E\u0432\u0438.`,
        invoices: fetched.map((f, i) => ({
          subject: f.subject,
          sender: f.senderName || f.senderEmail,
          filename: f.pdfFilename
        }))
      };
    } catch (err) {
      return {
        success: false,
        message: `\u0413\u0440\u0435\u0448\u043A\u0430: ${err.message}`,
        invoices: []
      };
    }
  }),
  // Листа на примени email фактури
  list: publicQuery.input(external_exports.object({
    status: external_exports.string().optional()
  }).optional()).query(async ({ input }) => {
    const db2 = getDb();
    let query = db2.select().from(emailInvoices).orderBy(desc(emailInvoices.createdAt));
    const result = await query;
    if (input?.status) {
      return result.filter((r) => r.status === input.status);
    }
    return result;
  }),
  // Match со добавувач
  matchSupplier: publicQuery.input(external_exports.object({ id: external_exports.number() })).mutation(async ({ input }) => {
    const db2 = getDb();
    const rows = await db2.select().from(emailInvoices).where(eq(emailInvoices.id, input.id));
    if (!rows[0]) return { success: false, message: "\u041D\u0435 \u0435 \u043F\u0440\u043E\u043D\u0430\u0458\u0434\u0435\u043D\u043E" };
    const matched = await matchSupplier(
      rows[0].senderEmail || "",
      rows[0].senderName || ""
    );
    if (matched) {
      await updateEmailInvoiceStatus(input.id, "parsed", {
        matchedSupplierId: matched.id,
        parsedSupplierName: matched.name
      });
      return { success: true, supplierName: matched.name, supplierId: matched.id };
    }
    return { success: false, message: "\u041D\u0435 \u0435 \u043F\u0440\u043E\u043D\u0430\u0458\u0434\u0435\u043D \u0434\u043E\u0431\u0430\u0432\u0443\u0432\u0430\u0447" };
  }),
  // Одобри -> креирај влезна фактура
  approve: publicQuery.input(external_exports.object({
    id: external_exports.number(),
    supplierId: external_exports.number(),
    supplierInvoiceNumber: external_exports.string(),
    totalAmount: external_exports.string(),
    issueDate: external_exports.string().optional()
  })).mutation(async ({ input }) => {
    await updateEmailInvoiceStatus(input.id, "imported");
    return { success: true };
  }),
  // Одбиј
  reject: publicQuery.input(external_exports.object({ id: external_exports.number() })).mutation(async ({ input }) => {
    await updateEmailInvoiceStatus(input.id, "rejected");
    return { success: true };
  }),
  // Избриши
  delete: publicQuery.input(external_exports.object({ id: external_exports.number() })).mutation(async ({ input }) => {
    const db2 = getDb();
    await db2.delete(emailInvoices).where(eq(emailInvoices.id, input.id));
    return { success: true };
  })
});

